const messages = $input.all();
let texts = [];

// The DB returns latest messages first. We want to skip anything PREVIOUS to a /clear
for (const m of messages) {
    const content = (m.json.content || m.json.message || '').trim();
    if (!content) continue;

    // If we hit a /clear command in history, stop accumulating!
    if (content.toLowerCase() === '/clear') {
        break;
    }
    texts.push(content);
}

// Reverse to chronological order (oldest un-cleared to newest)
const combinedText = texts.reverse().join('\n\n');

const latestMsg = messages.length > 0 ? messages[0].json : {};

return [{
  json: {
    ...latestMsg,
    isLastMessage: true,
    combinedText: combinedText || latestMsg.content || ''
  }
}];

const staticData = $getWorkflowStaticData('global');
const triggerPhone = $('WhatsApp Trigger').first().json.body?.data?.key?.remoteJid;
const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

let text = "";
const msg = $('WhatsApp Trigger').first().json.body?.data?.message;
if (msg) { text = msg.conversation || msg.extendedTextMessage?.text || ""; }

if (typeof staticData[triggerPhone] !== 'object') {
    const oldV = staticData[triggerPhone] || 1;
    staticData[triggerPhone] = { v: oldV, resetAt: "1970-01-01T00:00:00Z" };
}

let isClearCommand = false;
if (text.trim().toLowerCase() === '/clear') {
    staticData[triggerPhone].v += 1;
    staticData[triggerPhone].resetAt = new Date().toISOString();
    isClearCommand = true;
}

const finalResetAt = staticData[triggerPhone].resetAt || "1970-01-01T00:00:00Z";

return [{
    json: {
        memorySessionId: triggerPhone + "_" + today + "_v" + staticData[triggerPhone].v,
        resetAt: finalResetAt,
        isClearCommand: isClearCommand,
        text: text
    }
}];

